import React, { useState } from "react";

import {
    Container,
    Paper,
    Typography,
    TextField,
    Button
} from "@mui/material";

import { useNavigate } from "react-router-dom";

import { getUsers } from "../data/userStorage";

function Login() {

    const navigate = useNavigate();

    const [username, setUsername] = useState("");
    const [password, setPassword] = useState("");

    const login = () => {

        const users = getUsers();

        const validUser = users.find(
            user =>
                user.username === username &&
                user.password === password
        );

        if (validUser) {

            localStorage.setItem(
                "loggedInUser",
                JSON.stringify(validUser)
            );

            navigate("/dashboard");

        } else {

            alert("Invalid Username or Password");

        }
    };

    return (

        <Container
            maxWidth="sm"
            sx={{ mt: 10 }}
        >

            <Paper
                elevation={5}
                sx={{ p: 4 }}
            >

                <Typography
                    variant="h4"
                    align="center"
                >
                    5G AF IoT Portal
                </Typography>

                <br />

                <TextField
                    fullWidth
                    label="Username"
                    value={username}
                    onChange={(e) =>
                        setUsername(e.target.value)
                    }
                />

                <br />
                <br />

                <TextField
                    fullWidth
                    type="password"
                    label="Password"
                    value={password}
                    onChange={(e) =>
                        setPassword(e.target.value)
                    }
                />

                <br />
                <br />

                <Button
                    fullWidth
                    variant="contained"
                    onClick={login}
                >
                    Login
                </Button>

                <br />
                <br />

                <Typography
                    variant="body2"
                    align="center"
                >
                    Default Users:
                </Typography>

                <Typography
                    variant="body2"
                    align="center"
                >
                    admin / admin123
                </Typography>

                <Typography
                    variant="body2"
                    align="center"
                >
                    operator / operator123
                </Typography>

                <Typography
                    variant="body2"
                    align="center"
                >
                    viewer / viewer123
                </Typography>

            </Paper>

        </Container>

    );
}

export default Login;
